81	      variable write_address, read_address : natural := 0;
82	      variable num_bytes, num_segments : natural := 0;
83	    begin
84	      -- Make the buffer loop around a number of times.
85	      while num_processed < 5 * buffer_size_segments loop
86	        wait until buffer_written_address /= buffer_read_address and rising_edge(clk);
